use std::borrow::Cow;

fn process_string(s: &str) -> Cow<str> {
    if s.chars().all(|c| c.is_alphabetic()) {
        Cow::Borrowed(s)
    } else {
        let mut buf = String::new();
        for c in s.chars() {
            if c.is_alphabetic() { buf.push(c.to_ascii_uppercase()); }
        }
        Cow::Owned(buf)
    }
}

fn main() {
    let input = "hello world";
    let output = process_string(input);
    println!("{}", output);
