trait Process<'a> {
    fn process(&'a self) -> Cow<str>;
}

impl<'a> Process<'a> for str {
    fn process(&'a self) -> Cow<str> {
        if self.starts_with('A') {
            let mut s = self.to_string();
            s.push_str("_modified");
            Cow::Owned(s)
        } else {
            Cow::Borrowed(self)
        }
    }
}

